#include <stdio.h>
#include <stdlib.h>
#define MAX_N 1000
#define MAX_M 1000

// Structure to represent an edge
typedef struct Edge {
    int u, v;
} Edge;

// Function to perform the graph transformation
void transformGraph(Edge *edges, int M, int *vertices, int *edgesCount) {
    *edgesCount = 0;
    for (int i = 0; i < M; i++) {
        for (int j = i + 1; j < M; j++) {
            if (edges[i].u == edges[j].u || edges[i].u == edges[j].v || edges[i].v == edges[j].u || edges[i].v == edges[j].v) {
                (*edgesCount)++;
            }
        }
    }
    *vertices = M;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        Edge edges[M];
        for (int i = 0; i < M; i++) {
            scanf("%d %d", &edges[i].u, &edges[i].v);
        }
        int vertices, edgesCount;
        transformGraph(edges, M, &vertices, &edgesCount);
        transformGraph(edges, edgesCount, &vertices, &edgesCount);
        transformGraph(edges, edgesCount, &vertices, &edgesCount);
        printf("%d %d\n", vertices, edgesCount);
    }
    return 0;
}

