import java.util.Scanner;
public class Main {
    // Structure to represent an edge
    static class Edge {
        int u, v;
        Edge(int u, int v) {
            this.u = u;
            this.v = v;
        }
    }

    // Function to perform the graph transformation
    public static void transformGraph(Edge[] edges, int[] vertices, int[] edgesCount) {
        edgesCount[0] = 0;
        for (int i = 0; i < edges.length; i++) {
            for (int j = i + 1; j < edges.length; j++) {
                if (edges[i].u == edges[j].u || edges[i].u == edges[j].v || edges[i].v == edges[j].u || edges[i].v == edges[j].v) {
                    edgesCount[0]++;
                }
            }
        }
        vertices[0] = edges.length;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int M = scanner.nextInt();
            Edge[] edges = new Edge[M];
            for (int i = 0; i < M; i++) {
                edges[i] = new Edge(scanner.nextInt(), scanner.nextInt());
            }
            int[] vertices = new int[1];
            int[] edgesCount = new int[1];
            transformGraph(edges, vertices, edgesCount);
            transformGraph(edges, vertices, edgesCount);
            transformGraph(edges, vertices, edgesCount);
            System.out.println(vertices[0] + " " + edgesCount[0]);
        }
    }
}

