const lines = require('fs').readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

// Structure to represent an edge
class Edge {
    constructor(u, v) {
        this.u = u;
        this.v = v;
    }
}

// Function to perform the graph transformation
function transformGraph(edges) {
    let edgesCount = 0;
    for (let i = 0; i < edges.length; i++) {
        for (let j = i + 1; j < edges.length; j++) {
            if (edges[i].u === edges[j].u || edges[i].u === edges[j].v || edges[i].v === edges[j].u || edges[i].v === edges[j].v) {
                edgesCount++;
            }
        }
    }
    let vertices = edges.length;
    return [vertices, edgesCount];
}

